/**
 * @file lib/response.ts
 * @description Canonical HTTP response shapes for the sandbox gateway.
 *
 * EVERY response from this API — success or error — is wrapped in this
 * envelope. Consumers can always rely on `{ ok, data, error }`.
 *
 * Security notes
 * ──────────────
 * • Error responses NEVER include stack traces or internal paths.
 * • `requestId` is included on every response for distributed tracing.
 *   It is generated by the request middleware, not this module.
 * • `timestamp` is always UTC ISO 8601 — never expose local timezone.
 */
// ---------------------------------------------------------------------------
// Senders
// ---------------------------------------------------------------------------
export function sendSuccess(res, data, requestId, statusCode = 200) {
    const body = {
        ok: true,
        requestId,
        timestamp: new Date().toISOString(),
        data,
    };
    res.status(statusCode).json(body);
}
export function sendError(res, statusCode, code, message, requestId, details) {
    const body = {
        ok: false,
        requestId,
        timestamp: new Date().toISOString(),
        error: {
            code,
            message,
            ...(details !== undefined ? { details } : {}),
        },
    };
    res.status(statusCode).json(body);
}
// ---------------------------------------------------------------------------
// Common error shortcuts
// ---------------------------------------------------------------------------
export function send400(res, message, requestId, details) {
    sendError(res, 400, "VALIDATION_ERROR", message, requestId, details);
}
export function send401(res, requestId) {
    sendError(res, 401, "UNAUTHORIZED", "Authentication required.", requestId);
}
export function send403(res, requestId) {
    sendError(res, 403, "FORBIDDEN", "Access denied.", requestId);
}
export function send404(res, requestId) {
    sendError(res, 404, "NOT_FOUND", "The requested resource was not found.", requestId);
}
export function send405(res, requestId, allowed) {
    res.set("Allow", allowed.join(", "));
    sendError(res, 405, "METHOD_NOT_ALLOWED", `Allowed methods: ${allowed.join(", ")}`, requestId);
}
export function send429(res, requestId, retryAfterMs) {
    res.set("Retry-After", String(Math.ceil(retryAfterMs / 1000)));
    sendError(res, 429, "RATE_LIMITED", "Too many requests. Please slow down.", requestId);
}
export function send500(res, requestId) {
    sendError(res, 500, "INTERNAL_ERROR", "An unexpected error occurred. Please try again later.", requestId);
}
export function send409(res, message, requestId, code = "CONFLICT", details) {
    sendError(res, 409, code, message, requestId, details);
}
export function send503(res, requestId, message) {
    sendError(res, 503, "SERVICE_UNAVAILABLE", message ?? "Service temporarily unavailable. Please try again later.", requestId);
}
